import { Component } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { SiteviewService } from '../../core/services/siteview.service';

@Component({
  selector: 'app-admin-settings',
  standalone: true,
  imports: [CommonModule, FormsModule],
  templateUrl: './admin-settings.component.html',
  styleUrl: './admin-settings.component.css',
})
export class AdminSettingsComponent {
  readonly services = this.sv.serviceSettings;
  savedKey: string | null = null;

  constructor(private sv: SiteviewService) {}

  save(service: string, key: string, value: string): void {
    this.sv.updateServiceSetting(service, key, value);
    this.savedKey = `${service}:${key}`;
    setTimeout(() => (this.savedKey = null), 1500);
  }
}
